const incoming = $json.body || $json;
const message = incoming.message || {};

// Vapi can send the tool call in several shapes
const toolCall =
  message.toolCall ||
  incoming.toolCall ||
  message.toolCallList?.[0] ||
  message.toolCalls?.[0] ||
  incoming.toolCallList?.[0] ||
  incoming.toolCalls?.[0] ||
  message.toolWithToolCallList?.[0]?.toolCall ||
  incoming.toolWithToolCallList?.[0]?.toolCall ||
  null;

function parseMaybeJson(value) {
  if (typeof value !== "string") return value;

  try {
    return JSON.parse(value);
  } catch (e) {
    return {};
  }
}

let params =
  toolCall?.parameters ||
  toolCall?.arguments ||
  toolCall?.function?.arguments ||
  toolCall?.function?.parameters ||
  incoming;

params = parseMaybeJson(params);

// Some tools nest arguments one level deeper
if (params?.arguments) {
  params = parseMaybeJson(params.arguments);
}

let action = String(params.action || incoming.action || "book")
  .trim()
  .toLowerCase();

if (action === "cancellation") action = "cancel";
if (action === "cancel_booking") action = "cancel";

const toolCallId =
  toolCall?.id ||
  toolCall?.toolCallId ||
  toolCall?.callId ||
  toolCall?.function?.id ||
  null;

function clean(value) {
  if (value === undefined || value === null) return null;
  const text = String(value).trim();
  return text.length ? text : null;
}

function bool(value) {
  return value === true || value === "true" || value === "yes" || value === "Yes";
}

return [
  {
    json: {
      action,

      // Shared patient fields
      patient_name: clean(params.patient_name),
      patient_contact: clean(params.patient_contact),

      // Booking/cancellation matching fields
      service_code: clean(params.service_code),
      requested_start_time: clean(params.requested_start_time),
      urgency: clean(params.urgency) || "normal",

      // Waitlist fields
      waitlist_consent: bool(params.waitlist_consent),
      notification_email: clean(params.notification_email),

      // Cancellation fields
      booking_id: clean(params.booking_id),
      cancelled_by: clean(params.cancelled_by) || "patient_voice_call",
      cancellation_reason: clean(params.cancellation_reason) || "Patient requested cancellation",

      source_channel: "vapi_or_postman_workflow",

      // Vapi response fields
      is_vapi_tool_call: Boolean(toolCallId),
      tool_call_id: toolCallId,
      tool_name:
        clean(toolCall?.name) ||
        clean(toolCall?.function?.name) ||
        "bookDentalAppointment",

      original_body: incoming
    }
  }
];

