    error: raw.error
  };
} else {
  if (result.body !== undefined) result = result.body;
  if (result.data !== undefined) result = result.data;

  result = parseMaybeJson(result);

  if (Array.isArray(result)) {
    result = result[0] || {};
  }

  result = parseMaybeJson(result);
}

return [
