      ...result,
      raw_supabase_response: raw
    }
  }
];

function parseMaybeJson(value) {
  if (typeof value !== "string") return value;

  try {
    return JSON.parse(value);
  } catch (e) {
    return value;
  }
}

function plainError(error) {
  if (!error) return null;

  return {
    message: error.message || String(error),
    name: error.name || "Error",
    code: error.code || null,
    status: error.status || error.statusCode || null
  };
}

function makePlain(value) {
  if (value === null || value === undefined) return value;

  if (value instanceof Error) {
    return plainError(value);
  }

  if (Array.isArray(value)) {
    return value.map(makePlain);
  }

  if (typeof value === "object") {
    const output = {};

    for (const key of Object.keys(value)) {
      const current = value[key];

      if (current instanceof Error) {
        output[key] = plainError(current);
      } else if (typeof current === "object" && current !== null) {
        output[key] = makePlain(current);
      } else {
        output[key] = current;
      }
    }

    return output;
  }

  return value;
}

const rawInput = $input.first().json;
const raw = makePlain(rawInput);

let result = raw;

if (raw.error) {
  result = {
    status: "verification_required",
    message: "The cancellation request was submitted, but the system could not confirm the final result. Clinic staff should verify the appointment status.",
    error: makePlain(raw.error)
  };
} else {
  if (result.body !== undefined) result = result.body;
  if (result.data !== undefined) result = result.data;

  result = parseMaybeJson(result);

  if (Array.isArray(result)) {
    result = result[0] || {};
  }

  result = parseMaybeJson(result);
  result = makePlain(result);
}

return [
  {
    json: {
      ...result,
      raw_supabase_response: raw
    }
  }
];

const input = $input.first().json;

const FULL_RPC_URL = "https://YOUR_SUPABASE_PROJECT.supabase.co/rest/v1/rpc/try_book_slot";
const SERVICE_ROLE_KEY = "YOUR_SUPABASE_SERVICE_ROLE_KEY";

const payload = {
  p_patient_name: input.patient_name || null,
  p_patient_contact: input.patient_contact || null,
  p_service_code: input.service_code || null,
  p_requested_start_time: input.requested_start_time || null,
  p_urgency: input.urgency || "normal",
  p_source_channel: input.source_channel || "n8n_code_node",
  p_raw_payload: input.original_body || input,
  p_waitlist_consent: input.waitlist_consent === true,
  p_notification_email: input.notification_email || null
};

function sleep(ms) {
  return new Promise(resolve => setTimeout(resolve, ms));
}

let lastError = null;

for (let attempt = 1; attempt <= 4; attempt++) {
  try {
    const data = await this.helpers.httpRequest({
      method: "POST",
      url: FULL_RPC_URL,
      headers: {
        "apikey": SERVICE_ROLE_KEY,
        "Authorization": "Bearer " + SERVICE_ROLE_KEY,
        "Content-Type": "application/json"
      },
      body: payload,
      json: true,
      timeout: 10000
    });

    if (data && typeof data === "object" && !Array.isArray(data)) {
      data.rpc_attempt = attempt;
      return [{ json: data }];
    }

    return [
      {
        json: {
          data,
          rpc_attempt: attempt
        }
      }
    ];
  } catch (error) {
    lastError = {
      message: error.message || String(error),
      name: error.name || "Error",
      code: error.code || null,
      status: error.statusCode || error.status || null,
      attempt
    };

    if (attempt < 4) {
      await sleep(2000 * attempt);
    }
  }
}

return [
  {
    json: {
      error: lastError,
      attempted_payload: payload
    }
  }
];

